// A simple concurrent hash-based map
// Supports concurrent linearizable, insert, find and remove.
// size(), keys() don't linearize with updates.
// Requires the capacity to be  specified on construction.
// No more than the capacity distinct keys can ever be added.
// Once a key is added, removing it will empty the value and mark
// the key as deleted, but only a value with the same key can use the
// same slot (i.e. it still counts towards the capacity).
// It uses locks, but holds them very briefly.

output:
#include <cstddef>

#include <algorithm>
#include <atomic>
#include <optional>
#include <utility>

#include <parlay/primitives.h>
#include <parlay/sequence.h>













template <typename K,
	  typename V,
	  typename Hash = parlay::hash<K>,
	  typename Equal = std::equal_to<>>
struct hash_map {
 private:
  using KV = std::pair<K,V>;
  using index = unsigned long;
  long m;
  index first_index(K k) { return hash(k) % m;}
  index next_index(index h) { return (h + 1 == m) ? 0 : h + 1; }
  Hash hash;
  Equal equal;

  enum state : char {empty, full, locked, tomb};
  struct entry {
    std::atomic<state> status;
    K key;
    V value;
    entry() : status(empty) {}
  };
  parlay::sequence<entry> H;

 public:
  hash_map(long size, Hash&& hash = {}, Equal&& equal = {}) 
    : m(100 + static_cast<index>(1.5 * size)),
      hash(hash), equal(equal),
      H(parlay::sequence<entry>(m)) {}

  bool insert(const K& k, const V& v) {
    index i = first_index(k);
    long count = 0;
    while (true) {
      state status = H[i].status;
      if (status == full || status == tomb) {
	if (H[i].key == k) {
	  if (status == full) return false;
	  else if (H[i].status.compare_exchange_strong(status, locked)) {
	    H[i].value = v;
	    H[i].status = full;
	    return true;	    
	  }
	} else {
	  if (count++ == std::min(1000l,m)) {
	    std::cout << "Hash table overfull" << std::endl;
	    return false;
	  }
	  i = next_index(i);
	}
      } else if (status == empty) {
	if (H[i].status.compare_exchange_strong(status, locked)) {
	  H[i].key = k;
	  H[i].value = v;
	  H[i].status = full;
	  return true;
	}
      }
    }
  }

  std::optional<V> find(const K& k) {
    index i = first_index(k);
    while (true) {
      if (H[i].status != full) return {};
      if (H[i].key == k) return H[i].value;
      i = next_index(i);
    }
  }

  std::optional<V> remove(const K& k) {
    index i = first_index(k);
    while (true) {
      if (H[i].status == empty || H[i].status == locked) return {};
      if (H[i].key == k) {
	state old = full;
	if (H[i].status == full &&
	    H[i].status.compare_exchange_strong(old, tomb)) 
	  return std::move(H[i].value);
	else return {};
      }
      i = next_index(i);
    }
  }

  parlay::sequence<K> keys() {
    return parlay::map_maybe(H, [] (const entry &x) {
	return (x.status == full) ? std::optional{x.key} : std::optional<K>{};});
  }

  size_t size() {
    return parlay::reduce(parlay::delayed_map(H, [&] (auto const &x) -> long {
	  return x.status == full;}));
  }
};

instruction:
// Builds a huffman tree in parallel from a sequence of probabilities
// Sorts the probabilities and then pairs up all probabilities from
// the minimum value to twice that value.  Repeats until done.
// Returns a pointer to all leaves (for encoding), and to the root
// (for decoding).

output:
#include <tuple>
#include <algorithm>

#include <parlay/primitives.h>
#include <parlay/sequence.h>
#include <parlay/delayed.h>










struct node { bool is_leaf; node* parent;};

struct leaf : node {
  long idx;
  leaf(long i) : node{true, nullptr}, idx(i) {}
};

struct interior : node {
  node* L; node* R;
  interior(node* L, node* R) : node{false, nullptr}, L(L), R(R) {}
};

parlay::type_allocator<leaf> leaf_pool;
parlay::type_allocator<interior> interior_pool;

auto huffman_tree(const parlay::sequence<float>& probs) {


  auto leaves = parlay::tabulate(probs.size(), [&] (auto i) -> node* {
    return leaf_pool.allocate(i);});


  auto greater = [] (auto a, auto b) {return std::get<0>(a) > std::get<0>(b);};
  auto active = sort(parlay::delayed::zip(probs, leaves), greater);
  auto abegin = active.begin();



  auto search = [&] (float prob, long top) {
    auto x = std::lower_bound(abegin, abegin + top, prob,
                              [] (auto a, float p) {return std::get<0>(a) > p;});
    return x - abegin;};

  long top = active.size();


  float cutoff = 2 * std::get<0>(active[top-1]);
  long mid = search(cutoff, top);
  while (top > 1) {
    cutoff *= 2;

    if ((top - mid) % 2 == 1) mid++;


    auto pairs = parlay::tabulate((top-mid)/2, [&] (long i) {
      auto [lprob, lnode] = active[mid + 2*i];
      auto [rprob, rnode] = active[mid + 2*i + 1];
      float new_prob = lprob + rprob;
      node* new_node = interior_pool.allocate(lnode, rnode);
      lnode->parent = rnode->parent = new_node;
      return std::tuple<float,node*>{new_prob, new_node};});


    long bot = search(cutoff, mid);


    auto merged = parlay::merge(pairs, active.cut(bot,mid), greater);


    top = bot + merged.size();
    mid = bot;
    parlay::copy(merged, active.cut(mid, top));
  }
  return std::tuple{leaves, std::get<1>(active[0])};
}

void delete_tree(node* T, int depth=0) { 
  if (T->is_leaf)
    leaf_pool.retire(static_cast<leaf*>(T));
  else {
    interior* TI = static_cast<interior*>(T);
    parlay::par_do_if(depth < 16,
                      [&] {delete_tree(TI->L, depth+1);},
                      [&] {delete_tree(TI->R, depth+1);});
    interior_pool.retire(TI);
  }
}

instruction:
// Karatsuba's algorithm for multiplying big integers
// Assumes integers are non-negative.
// Uses big integer addition and subtraction from bigint_add.h

output:
#include <algorithm>
#include <array>
#include <limits>

#include <parlay/primitives.h>
#include <parlay/sequence.h>
#include <parlay/delayed.h>

#include "bigint_add.h"








template <typename Bigint>
bigint small_multiply(const Bigint& a, const Bigint& b);


auto shift(const bigint& a, int n) {
  return parlay::delayed::tabulate(a.size() + n, [&,n] (long i) {
      return (i < n) ? 0 : a[i-n];});}


template <typename Bigint>
bigint karatsuba(const Bigint& a, const Bigint& b) {
  long na = a.size();  long nb = b.size();
  if (na < nb) return karatsuba(b,a);
  if (nb <= 128) return small_multiply(a,b);
  long nhalf = nb/2;
  auto low_a = a.cut(0, nhalf);  auto high_a = a.cut(nhalf, na);
  auto low_b = b.cut(0, nhalf);  auto high_b = b.cut(nhalf, nb);
  bigint z0, z1, z2;
  parlay::par_do3([&] {z0 = karatsuba(low_a, low_b);},
                  [&] {z1 = karatsuba(add(low_a, high_a), add(low_b, high_b));},
                  [&] {z2 = karatsuba(high_a, high_b);});

  auto mid = subtract(z1, add(z0, z2));
  return add(shift(z2, 2 * nhalf), add(shift(mid, nhalf), z0));
}




template <typename Bigint>
bigint small_multiply(const Bigint& a, const Bigint& b) {
  long na = a.size();  long nb = b.size();
  if (na < nb) return small_multiply(b, a);
  double_digit mask = (static_cast<double_digit>(1) << digit_len) - 1;


  bigint result(na + nb, 0);
  for (long i = 0; i < na + nb -1; i++) {
    double_digit accum = result[i];
    for (long j = std::max(0l, i-nb+1); j < std::min(i + 1, nb); j++)
      accum += a[j]*b[i-j];
    result[i] = accum & mask;
    result[i+1] = (accum >> digit_len); 
  }
  return result;
}

instruction:
// Find the kcore number (degeneracy), and "coreness" of each vertex
// of an undirected graph.
// Uses parallel peeling and is work efficient.

output:
#include <algorithm>
#include <utility>

#include <parlay/primitives.h>
#include <parlay/sequence.h>






template <typename vertex>
using graph = parlay::sequence<parlay::sequence<vertex>>;

template <typename vertex>
auto kcore(graph<vertex>& G) {
  using namespace parlay;
  int n = G.size();
  auto done = sequence<bool>(n, false);
  auto d = map(G, [] (auto& ngh) -> vertex {return ngh.size();});
  vertex maxd = reduce(d, maximum<vertex>())+1;
  auto di = tabulate(n, [&] (vertex i) {return std::pair(d[i], i);});
  auto buckets = map(group_by_index(di,maxd), [] (auto& b) {return graph<vertex>(1,b);});
  vertex k = 0;
  long total = 0;

  while (total < n) {
    auto b = filter(flatten(buckets[k]),
                    [&] (auto v) { return done[v] ? false : (done[v] = true);});
    buckets[k].clear();
    if (b.size() == 0) {k++; continue;}
    total += b.size();
    auto ngh = filter(flatten(map(b, [&] (auto v) {return G[v];})),
                      [&] (auto u) {return d[u] > k;});
    auto u = map(histogram_by_key<vertex>(ngh), [&] (auto uc) {
      auto [u, c] = uc;
      d[u] = std::max(k, d[u] - c);
      return std::pair(d[u], u);});
    for_each(group_by_key_ordered(u), [&] (auto& dv) {
      auto [d,v] = dv;
      buckets[d].push_back(std::move(v));});
  }
  return d;
}

