template <typename vertex, typename wtype>
using edges = parlay::sequence<std::tuple<vertex,vertex,wtype>>;


template <typename vertex, typename wtype>
parlay::sequence<long> min_spanning_forest(const edges<vertex,wtype>& E, long n) {
  using indexed_edge = std::tuple<wtype,long,vertex,vertex>;
  long m = E.size();

  parlay::sequence<bool> inMST(m, false); 
  union_find<vertex> UF(n);
  parlay::sequence<reservation<long>> R(n); 


  auto EI = parlay::delayed_tabulate(m, [&] (long i) {
    auto [u,v,w] = E[i];
    return indexed_edge(w, i, u, v);});

  auto SEI = parlay::sort(EI);



  auto reserve = [&] (long i) {
    auto [w, id, u, v] = SEI[i];
    u = UF.find(u);
    v = UF.find(v);
    if (u != v) {
      R[v].reserve(i);
      R[u].reserve(i);
      return try_commit;
    } else return done;
  };





  auto commit = [&] (long i) {
    auto [w, id, u, v] = SEI[i];
    u = UF.find(u);
    v = UF.find(v);
    if (R[v].check(i)) {
      R[u].check_reset(i);
      UF.link(v, u);     
      inMST[id] = true;
      return true;}
    else if (R[u].check(i)) {
      UF.link(u, v);    
      inMST[id] = true;
      return true; }
    else return false;
  };


  speculative_for<vertex>(0, m, reserve, commit);


  return parlay::pack_index<long>(inMST);
}

